pub struct BootImage { bytes: &'static [u8], count: usize }

impl BootImage {
    pub fn get() -> Self {
        let bytes = BOOT_IMAGE;
        assert!(rd_u32(bytes, 0) == MXBI_MAGIC);
        let count = rd_u32(bytes, 8) as usize;
        Self { bytes, count }
    }

    pub fn iter(&self) -> BootImageIter {
        BootImageIter { bytes: self.bytes, count: self.count, idx: 0 }
    }
}

pub struct BootImageIter { ... }
impl Iterator for BootImageIter {
    fn next(&mut self) -> Option<(ProcNr, &'static [u8])> {
        if self.idx >= self.count { return None; }
        let (nr, elf) = proc_and_elf(self.bytes, self.idx);
        self.idx += 1;
        Some((nr, elf))
    }
}
```

