**load_boot_server function** (lines 265–314):
```rust
unsafe fn load_boot_server(nr: ProcNr, elf: &[u8], stack_va: u64) {
    let mut aspace = AddrSpace::new()?;
    let entry = crate::boot_image::elf::load_into(elf, &mut aspace)?;

    let stack_frame = alloc_frame()?;
    aspace.map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)?;

    let asid = alloc_asid();

    let p = proc_slot_mut(nr)?;
    p.regs.elr_el1 = entry;           // ELF entry point
    p.regs.sp_el0 = stack_va + PAGE_SIZE as u64;
    p.ttbr0_pa = aspace.ttbr0_pa;
    p.asid = asid;
    p.rts_flags.store(0, Ordering::Relaxed);  // Clear RTS_NO_PRIV

    sched::enqueue(nr);  // Add to run queue
}
```

