1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! Kernel-call dispatch — the `SYSTEM` task's role.
4	//!
5	//! In MINIX 3, `SYSTEM` is a kernel pseudo-task: it has a proc-table slot but
6	//! no scheduler context. When a server `SENDREC`s the `SYSTEM` endpoint, the
7	//! IPC fast path in `proc.c::do_ipc` short-circuits into `kernel_call()`
8	//! (`kernel/system.c`), which runs synchronously in the *caller's* EL1 stack
9	//! and writes the reply back into the caller's user buffer. The caller never
10	//! actually blocks on a receiver; SYSTEM's `IMAGE` entry exists only so that
11	//! the endpoint encodes to a valid `ProcNr`.
12	//!
13	//! minix.rs inherits exactly that shape. [`ipc::dispatch`] detects
14	//! `src_dst_e == boot_endpoint(SYSTEM)` in the SENDREC arm and diverts here
15	//! instead of calling [`ipc::send::mini_send`]; the rest of the IPC engine is
16	//! untouched.
17	//!
18	//! [`ipc::dispatch`]: crate::ipc
19	//! [`ipc::send::mini_send`]: crate::ipc
20	
21	mod do_getinfo;
22	mod do_schedule;
23	mod do_vmctl;
24	mod stubs;
25	
26	use core::fmt::Write;
27	use core::sync::atomic::{AtomicU64, Ordering};
28	
29	use minixrs_kernel_shared::ProcNr;
30	use minixrs_kernel_shared::callnr::{
31	    KERNEL_CALL, NR_KERN_CALLS_PHASE4, NR_SYS_CALLS, SYS_COPY, SYS_DIAGCTL, SYS_EXEC, SYS_EXIT,
32	    SYS_FORK, SYS_GETINFO, SYS_IRQCTL, SYS_PRIVCTL, SYS_SAFECOPY, SYS_SCHEDCTL, SYS_SCHEDULE,
33	    SYS_SETALARM, SYS_SETGRANT, SYS_TIMES, SYS_VMCTL,
34	};
35	use minixrs_kernel_shared::com::{NR_SYS_PROCS, SYSTEM, boot_endpoint};
36	use minixrs_kernel_shared::endpoint::Endpoint;
37	use minixrs_kernel_shared::error::{EBADREQUEST, ECALLDENIED, OK};
38	use minixrs_kernel_shared::message::Message;
39	
40	use crate::ipc::{copy_msg_from_user, copy_msg_to_user};
41	use crate::proc::bitmap::{get_call_bit, get_sys_bit};
42	use crate::proc::table::{N_PROC_SLOTS, proc_index};
43	use crate::proc::{Priv, Proc};
44	use crate::uart::Uart;
45	
46	/// Boot-time endpoint of the `SYSTEM` kernel task. Generation never bumps for
47	/// kernel tasks in Phase 2 — they are statically slotted at boot and never
48	/// exit — so this single constant identifies SYSTEM for the entire kernel
49	/// lifetime.
50	#[inline]
51	pub fn system_endpoint() -> Endpoint {
52	    boot_endpoint(SYSTEM)
53	}
54	
55	/// Cadence of the boot-time kernel-call trace. Mirrors `ipc::TRACE_EVERY`.
56	const KCALL_TRACE_EVERY: u64 = 100;
57	/// Running total of kernel calls dispatched, sampled by the trace.
58	static CALL_COUNT: AtomicU64 = AtomicU64::new(0);
59	
60	/// `SENDREC`-to-SYSTEM fast path.
61	///
62	/// Reads the request out of `user_msg_va`, runs the dispatcher, and writes
63	/// the reply (m_source = SYSTEM, m_type = result, possibly mutated payload)
64	/// back to the same buffer. The caller stays runnable and `el1_svc_tail`
65	/// resumes it on return.
66	///
67	/// Returns the IPC-layer result (`OK`, `EFAULT`, `ECALLDENIED`); the
68	/// kernel-call result code is carried in the reply's `m_type` field.
69	pub fn kernel_call_sendrec(
70	    proc_table: &mut [Proc; N_PROC_SLOTS],
71	    priv_table: &mut [Priv; NR_SYS_PROCS],
72	    caller_nr: ProcNr,
73	    user_msg_va: u64,
74	) -> i32 {
75	    // Kernel invariants: any proc that reached the SVC handler has a slot
76	    // and a priv_id installed (proc::init or userland_bootstrap), and
77	    // SYSTEM is populated by proc::init. A None here is a structural bug
78	    // in those bootstrap paths, not a user-recoverable error — panic at
79	    // the call site rather than mask it behind ECALLDENIED.
80	    let caller_idx = proc_index(caller_nr).expect("caller in proc table");
81	    let caller_priv_id = proc_table[caller_idx]
82	        .priv_id
83	        .expect("caller priv populated");
84	    let system_idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
85	    let system_priv_id = proc_table[system_idx]
86	        .priv_id
87	        .expect("SYSTEM priv populated by proc::init");
88	
89	    // Apply the same ipc_to permission check that `mini_send` does
90	    // (`ipc/send.rs:59`) — the SYSTEM endpoint isn't a special trust
91	    // boundary, just a routing shortcut, so a caller without SYSTEM in its
92	    // ipc_to bitmap must still be denied here.
93	    if !get_sys_bit(
94	        &priv_table[caller_priv_id.as_usize()].ipc_to,
95	        system_priv_id,
96	    ) {
97	        return ECALLDENIED;
98	    }
99	
100	    let mut msg = match copy_msg_from_user(user_msg_va) {
101	        Ok(m) => m,
102	        Err(e) => return e,
103	    };
104	    let original_m_type = msg.m_type;
105	
106	    // Stamp m_source so handlers see the verified caller endpoint rather
107	    // than whatever the user scribbled into the request.
108	    msg.m_source = proc_table[caller_idx].endpoint;
109	
110	    // Dispatch. Most handlers want a single caller slot, but `do_vmctl`
111	    // operates on a *target* proc named in the message, so it needs the whole
112	    // table — pass the full slices and let the dispatcher hand each handler
113	    // what it needs.
114	    let result = kernel_call_dispatch(proc_table, priv_table, caller_nr, &mut msg);
115	
116	    // Build the reply.
117	    msg.m_source = system_endpoint();
118	    msg.m_type = result;
119	    if let Err(e) = copy_msg_to_user(user_msg_va, &msg) {
120	        return e;
121	    }
122	
123	    let n = CALL_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
124	    if n % KCALL_TRACE_EVERY == 0 {
125	        let call_idx = original_m_type - KERNEL_CALL;
126	        let mut uart = Uart::new();
127	        let _ = writeln!(
128	            uart,
129	            "[ksys {n}] caller={caller_nr} call={call_idx} result={result}",
130	        );
131	    }
132	
133	    OK
134	}
135	
136	/// Per-call dispatcher.
137	///
138	/// Steps: range-check `m_type - KERNEL_CALL`, gate against
139	/// `Priv::k_call_mask`, then route to the handler. Returns the result code
140	/// that becomes the reply's `m_type`.
141	///
142	/// `SYS_VMCTL` / `SYS_SCHEDULE` / `SYS_SCHEDCTL` act on a *target* proc named in
143	/// the message, so they take the whole `proc_table` + `caller_nr`. Every other
144	/// handler acts only on the caller, so it gets a single caller slot re-borrowed
145	/// inside its arm (see [`dispatch_caller_local`]).
146	fn kernel_call_dispatch(
147	    proc_table: &mut [Proc; N_PROC_SLOTS],
148	    priv_table: &[Priv; NR_SYS_PROCS],
149	    caller_nr: ProcNr,
150	    msg: &mut Message,
151	) -> i32 {
152	    let caller_idx = proc_index(caller_nr).expect("caller in proc table");
153	    let caller_priv_id = proc_table[caller_idx]
154	        .priv_id
155	        .expect("caller priv populated");
156	
157	    let call_idx = msg.m_type - KERNEL_CALL;
158	    if call_idx < 0 || (call_idx as usize) >= NR_SYS_CALLS {
159	        return EBADREQUEST;
160	    }
161	    let call_idx = call_idx as usize;
162	
163	    if !get_call_bit(&priv_table[caller_priv_id.as_usize()].k_call_mask, call_idx) {
164	        return ECALLDENIED;
165	    }
166	
167	    // Calls that act on a *target* proc named in the message take the whole
168	    // table + caller_nr; route them before the caller-local dispatch.
169	    match msg.m_type {
170	        SYS_VMCTL => return do_vmctl::do_vmctl(proc_table, caller_nr, msg),
171	        SYS_SCHEDULE => return do_schedule::do_schedule(proc_table, caller_nr, msg),
172	        SYS_SCHEDCTL => return do_schedule::do_schedctl(proc_table, caller_nr, msg),
173	        _ => {}
174	    }
175	
176	    // proc_table and priv_table are disjoint statics, so borrowing one slot
177	    // in each is permitted.
178	    let caller = &mut proc_table[caller_idx];
179	    let caller_priv = &priv_table[caller_priv_id.as_usize()];
180	    dispatch_caller_local(caller, caller_priv, msg)
181	}
182	
183	/// Dispatch the caller-only kernel calls (everything except `SYS_VMCTL`).
184	///
185	/// The const assert locks the arm count — adding a new `SYS_*` without a new
186	/// arm here is a compile error.
187	fn dispatch_caller_local(caller: &mut Proc, caller_priv: &Priv, msg: &mut Message) -> i32 {
188	    const _: () = assert!(
189	        NR_KERN_CALLS_PHASE4 == 15,
190	        "expand kernel_call_dispatch when a new SYS_* lands",
191	    );
192	    match msg.m_type {
193	        SYS_GETINFO => do_getinfo::do_getinfo(caller, caller_priv, msg),
194	        SYS_PRIVCTL => stubs::do_privctl(caller, caller_priv, msg),
195	        SYS_FORK => stubs::do_fork(caller, caller_priv, msg),
196	        SYS_EXEC => stubs::do_exec(caller, caller_priv, msg),
197	        SYS_EXIT => stubs::do_exit(caller, caller_priv, msg),
198	        SYS_COPY => stubs::do_copy(caller, caller_priv, msg),
199	        SYS_SAFECOPY => stubs::do_safecopy(caller, caller_priv, msg),
200	        SYS_IRQCTL => stubs::do_irqctl(caller, caller_priv, msg),
201	        // SYS_VMCTL / SYS_SCHEDULE / SYS_SCHEDCTL are handled in
202	        // `kernel_call_dispatch` (they act on a target proc and need the table).
203	        SYS_SETALARM => stubs::do_setalarm(caller, caller_priv, msg),
204	        SYS_TIMES => stubs::do_times(caller, caller_priv, msg),
205	        SYS_DIAGCTL => stubs::do_diagctl(caller, caller_priv, msg),
206	        SYS_SETGRANT => stubs::do_setgrant(caller, caller_priv, msg),
207	        _ => EBADREQUEST,
208	    }
209	}
210

