2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! minix.rs SCHED (scheduler) server.
4	//!
5	//! The user-space scheduler (slice 4.3). minix.rs keeps a priority-banded run
6	//! queue in the kernel but makes it *delegatable*: a proc whose
7	//! `Proc::scheduler` names SCHED is handed to SCHED on quantum exhaustion. The
8	//! kernel sends `SCHEDULING_NO_QUANTUM` (`m_source` = the preempted proc) and
9	//! leaves the proc off the run queue; SCHED runs its policy and re-admits the
10	//! proc via `SYS_SCHEDULE`. This mirrors MINIX 3's distinctive design while
11	//! keeping the proven kernel run queue as the kernel-scheduled fallback.
12	//!
13	//! Requests handled:
14	//! - `SCHEDULING_NO_QUANTUM` (kernel → SCHED): re-admit the preempted proc.
15	//! - `SCHEDULING_START` / `SCHEDULING_STOP` / `SCHEDULING_SET_NICE` (PM/RS →
16	//!   SCHED): claim / release / renice a managed proc. Implemented here for PM/RS
17	//!   to drive from slice 4.5+; in 4.3 the kernel pre-delegates a busy stub
18	//!   directly, so only the `NO_QUANTUM` round-trip is exercised live.
19	//!
20	//! Built as a freestanding aarch64 ELF (`servers/sched/user.ld`), packed into
21	//! the boot-image archive by `kernel/build.rs`, and loaded into its own
22	//! per-process AddrSpace at boot. Like every server it drives its loop through
23	//! the SEF framework ([`minixrs_server_rt`]); the policy lives in [`policy`],
24	//! whose pure logic carries the host unit tests.
25	
26	// Freestanding for the real (bare-metal) build, but a normal host binary under
27	// `cargo test` so `policy`'s logic gets host-runnable unit tests. The test
28	// harness needs `std` and its own entry point, so `no_std`/`no_main` and the
29	// `_start` shim below are all gated to `not(test)`.
30	#![cfg_attr(not(test), no_std)]
31	#![cfg_attr(not(test), no_main)]
32	
33	mod policy;
34	
35	use minixrs_ipc::{ipc_send, ipc_sendrec};
36	use minixrs_kernel_shared::Message;
37	use minixrs_kernel_shared::callnr::{
38	    SCHEDCTL_FLAG_KERNEL, SCHEDULING_NO_QUANTUM, SCHEDULING_SET_NICE, SCHEDULING_START,
39	    SCHEDULING_STOP, SYS_GETINFO_NAME_LEN, SYS_SCHEDCTL, SYS_SCHEDULE,
40	};
41	use minixrs_kernel_shared::com::{SYSTEM, boot_endpoint};
42	use minixrs_kernel_shared::endpoint::{Endpoint, endpoint_proc};
43	use minixrs_kernel_shared::error::OK;
44	use minixrs_server_rt::{SefConfig, sef_publish_to_ds, sef_startup};
45	
46	/// ELF entry point. The kernel primes `SP_EL0` before `eret`, so `_start` can
47	/// dive straight into Rust without setting up a stack itself.
48	// Gate the whole shim to `not(test)`: under `cargo test` the crate links as a
49	// normal host executable, and an exported `_start` would collide with the C
50	// runtime's `_start`. `.text._start` is an ELF section name, gated to the
51	// bare-metal target so `cargo check --workspace` on a Mach-O host still
52	// type-checks (the host rejects the specifier).
53	#[cfg(not(test))]
54	#[unsafe(no_mangle)]
55	#[cfg_attr(target_os = "none", unsafe(link_section = ".text._start"))]
56	pub extern "C" fn _start() -> ! {
57	    main()
58	}
59	
60	// Only `_start` calls `main`; under `cargo test` `_start` is gone, so `main`
61	// (and the helpers it alone reaches) would read as dead code.
62	#[cfg_attr(test, allow(dead_code))]
63	fn main() -> ! {
64	    // `sef_startup` learns SCHED's endpoint/name via SYS_GETINFO(GET_WHOAMI) and
65	    // runs `sched_init`, which publishes SCHED's endpoint to DS. No signal
66	    // handling. If startup fails there is no recovery and nothing to print from
67	    // EL0 — park forever.
68	    let sef = sef_startup(SefConfig {
69	        init_fresh: Some(sched_init),
70	        signal_handler: None,
71	    })
72	    .unwrap_or_else(|_| {
73	        loop {
74	            core::hint::spin_loop()
75	        }
76	    });
77	
78	    let system = boot_endpoint(SYSTEM);
79	    let mut msg = Message {
80	        m_source: 0,
81	        m_type: 0,
82	        payload: [0u8; 96],
83	    };
84	    loop {
85	        if sef.receive(&mut msg) != 0 {
86	            continue;
87	        }
88	        match msg.m_type {
89	            // Kernel → SCHED: re-admit the preempted proc (one-way, no reply).
90	            SCHEDULING_NO_QUANTUM => handle_no_quantum(system, msg.m_source),
91	            // PM/RS → SCHED requests (SENDREC; reply to the caller).
92	            SCHEDULING_START => handle_start(system, &mut msg),
93	            SCHEDULING_STOP => handle_stop(system, &mut msg),
94	            SCHEDULING_SET_NICE => handle_set_nice(system, &mut msg),
95	            // Unknown request: drop it.
96	            _ => {}
97	        }
98	    }
99	}
100	
101	/// SEF fresh-init callback: publish SCHED's endpoint to DS under its name, so
102	/// PM/RS can look SCHED up by name (slice 4.2). DS registers the caller's
103	/// kernel-stamped endpoint, so the `GET_WHOAMI` endpoint is not sent.
104	#[cfg_attr(test, allow(dead_code))]
105	fn sched_init(_endpoint: Endpoint, name: &[u8; SYS_GETINFO_NAME_LEN]) -> i32 {
106	    sef_publish_to_ds(name)
107	}
108	
109	/// `SCHEDULING_NO_QUANTUM` (kernel → SCHED): the proc identified by `preempted_e`
110	/// used its full quantum and is blocked off the run queue. Look up (lazily
111	/// registering) its policy state and re-admit it via `SYS_SCHEDULE`. No reply —
112	/// the kernel-originated notification is one-way; `SYS_SCHEDULE` is what unblocks
113	/// the proc.
114	#[cfg_attr(test, allow(dead_code))]
115	fn handle_no_quantum(system: Endpoint, preempted_e: Endpoint) {
116	    let proc_nr = endpoint_proc(preempted_e).get();
117	    // Table full (≥16 managed procs): can't manage this one — leave it blocked.
118	    // With a single pre-delegated stub in 4.3 this never happens.
119	    if let Some((priority, quantum)) = policy::schedule_proc(proc_nr) {
120	        sys_schedule(system, preempted_e, priority, quantum);
121	    }
122	}
123	
124	/// `SCHEDULING_START` (PM/RS → SCHED): begin scheduling `target` at the given
125	/// priority/quantum. Claim it via `SYS_SCHEDCTL`, record its policy state, and
126	/// assign the initial priority/quantum via `SYS_SCHEDULE`. Reply `OK` to the
127	/// caller. (Driven by PM/RS from slice 4.5+.)
128	#[cfg_attr(test, allow(dead_code))]
129	fn handle_start(system: Endpoint, msg: &mut Message) {
130	    let caller_e = msg.m_source;
131	    let target_e: Endpoint = rd_i32(msg, 0);
132	    let priority = rd_i32(msg, 4);
133	    let quantum = rd_i32(msg, 8);
134	
135	    sys_schedctl(system, target_e, 0); // claim: scheduler = SCHED
136	    policy::record(endpoint_proc(target_e).get(), priority as u8, quantum);
137	    sys_schedule(system, target_e, priority as u8, quantum);
138	
139	    reply(caller_e, msg, OK);
140	}
141	
142	/// `SCHEDULING_STOP` (PM/RS → SCHED): stop scheduling `target` and hand it back
143	/// to the kernel scheduler. Reply `OK` to the caller.
144	#[cfg_attr(test, allow(dead_code))]
145	fn handle_stop(system: Endpoint, msg: &mut Message) {
146	    let caller_e = msg.m_source;
147	    let target_e: Endpoint = rd_i32(msg, 0);
148	
149	    sys_schedctl(system, target_e, SCHEDCTL_FLAG_KERNEL); // release
150	    policy::forget(endpoint_proc(target_e).get());
151	
152	    reply(caller_e, msg, OK);
153	}
154	
155	/// `SCHEDULING_SET_NICE` (PM/RS → SCHED): change `target`'s band only, preserving
156	/// the quantum recorded at `SCHEDULING_START`, and apply it via `SYS_SCHEDULE`.
157	/// Reply `OK` to the caller.
158	#[cfg_attr(test, allow(dead_code))]
159	fn handle_set_nice(system: Endpoint, msg: &mut Message) {
160	    let caller_e = msg.m_source;
161	    let target_e: Endpoint = rd_i32(msg, 0);
162	    let priority = rd_i32(msg, 4);
163	
164	    // A renice changes the priority band only; `renice` keeps the proc's recorded
165	    // quantum (or registers at the default if unseen) and hands back the quantum
166	    // to re-schedule with. `None` only when the table is full and the proc is new.
167	    if let Some(quantum) = policy::renice(endpoint_proc(target_e).get(), priority as u8) {
168	        sys_schedule(system, target_e, priority as u8, quantum);
169	    }
170	
171	    reply(caller_e, msg, OK);
172	}
173	
174	/// Issue `SYS_SCHEDULE(target, priority, quantum)` to the kernel (SENDREC to
175	/// SYSTEM). The kernel sets the target's band + quantum and (re-)admits it to
176	/// the run queue. The reply code is ignored — a failure leaves the proc blocked,
177	/// which is the same outcome as not scheduling it.
178	#[cfg_attr(test, allow(dead_code))]
179	fn sys_schedule(system: Endpoint, target: Endpoint, priority: u8, quantum: i32) {
180	    let mut m = Message {
181	        m_source: 0,
182	        m_type: SYS_SCHEDULE,
183	        payload: [0u8; 96],
184	    };
185	    wr_i32(&mut m, 0, target);
186	    wr_i32(&mut m, 4, priority as i32);
187	    wr_i32(&mut m, 8, quantum);
188	    let _ = ipc_sendrec(system, &mut m);
189	}
190	
191	/// Issue `SYS_SCHEDCTL(flags, target)` to the kernel (SENDREC to SYSTEM):
192	/// `flags = 0` claims the target for SCHED; `SCHEDCTL_FLAG_KERNEL` releases it.
193	#[cfg_attr(test, allow(dead_code))]
194	fn sys_schedctl(system: Endpoint, target: Endpoint, flags: i32) {
195	    let mut m = Message {
196	        m_source: 0,
197	        m_type: SYS_SCHEDCTL,
198	        payload: [0u8; 96],
199	    };
200	    wr_i32(&mut m, 0, flags);
201	    wr_i32(&mut m, 4, target);
202	    let _ = ipc_sendrec(system, &mut m);
203	}
204	
205	/// Reply to a SENDREC caller with `code` in `m_type`.
206	#[cfg_attr(test, allow(dead_code))]
207	fn reply(caller_e: Endpoint, msg: &mut Message, code: i32) {
208	    msg.m_type = code;
209	    msg.m_source = 0; // kernel overwrites on delivery
210	    let _ = ipc_send(caller_e, msg);
211	}
212	
213	/// Read a native-endian i32 from payload `off..off+4` (mirrors the VM/DS helpers).
214	#[cfg_attr(test, allow(dead_code))]
215	fn rd_i32(m: &Message, off: usize) -> i32 {
216	    i32::from_ne_bytes(
217	        m.payload[off..off + 4]
218	            .try_into()
219	            .expect("payload in range"),
220	    )
221	}
222	
223	/// Write a native-endian i32 into payload `off..off+4`.
224	#[cfg_attr(test, allow(dead_code))]
225	fn wr_i32(m: &mut Message, off: usize, v: i32) {
226	    m.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
227	}
228	
229	// The freestanding panic handler; under `cargo test` std supplies its own.
230	#[cfg(not(test))]
231	#[panic_handler]
232	fn panic(_: &core::panic::PanicInfo) -> ! {
233	    loop {
234	        core::hint::spin_loop()
235	    }
236	}
