    // runs `sched_init`, which publishes SCHED's endpoint to DS. No signal
    // handling. If startup fails there is no recovery and nothing to print from
    // EL0 — park forever.
    let sef = sef_startup(SefConfig {
        init_fresh: Some(sched_init),
        signal_handler: None,
    })
    .unwrap_or_else(|_| {
        loop {
            core::hint::spin_loop()
        }
    });

    let system = boot_endpoint(SYSTEM);
    let mut msg = Message {
        m_source: 0,
        m_type: 0,
        payload: [0u8; 96],
    };
    loop {
        if sef.receive(&mut msg) != 0 {
            continue;
        }
        match msg.m_type {
            // Kernel → SCHED: re-admit the preempted proc (one-way, no reply).
            SCHEDULING_NO_QUANTUM => handle_no_quantum(system, msg.m_source),
            // PM/RS → SCHED requests (SENDREC; reply to the caller).
            SCHEDULING_START => handle_start(system, &mut msg),
            SCHEDULING_STOP => handle_stop(system, &mut msg),
            SCHEDULING_SET_NICE => handle_set_nice(system, &mut msg),
            // Unknown request: drop it.
            _ => {}
        }
    }
}

/// SEF fresh-init callback: publish SCHED's endpoint to DS under its name, so
/// PM/RS can look SCHED up by name (slice 4.2). DS registers the caller's
/// kernel-stamped endpoint, so the `GET_WHOAMI` endpoint is not sent.
#[cfg_attr(test, allow(dead_code))]
fn sched_init(_endpoint: Endpoint, name: &[u8; SYS_GETINFO_NAME_LEN]) -> i32 {
    sef_publish_to_ds(name)
}

/// `SCHEDULING_NO_QUANTUM` (kernel → SCHED): the proc identified by `preempted_e`
/// used its full quantum and is blocked off the run queue. Look up (lazily
/// registering) its policy state and re-admit it via `SYS_SCHEDULE`. No reply —
/// the kernel-originated notification is one-way; `SYS_SCHEDULE` is what unblocks
/// the proc.
#[cfg_attr(test, allow(dead_code))]
fn handle_no_quantum(system: Endpoint, preempted_e: Endpoint) {
    let proc_nr = endpoint_proc(preempted_e).get();
    // Table full (≥16 managed procs): can't manage this one — leave it blocked.
    // With a single pre-delegated stub in 4.3 this never happens.
    if let Some((priority, quantum)) = policy::schedule_proc(proc_nr) {
        sys_schedule(system, preempted_e, priority, quantum);
    }
}

/// `SCHEDULING_START` (PM/RS → SCHED): begin scheduling `target` at the given
/// priority/quantum. Claim it via `SYS_SCHEDCTL`, record its policy state, and
/// assign the initial priority/quantum via `SYS_SCHEDULE`. Reply `OK` to the
/// caller. (Driven by PM/RS from slice 4.5+.)
#[cfg_attr(test, allow(dead_code))]
fn handle_start(system: Endpoint, msg: &mut Message) {
    let caller_e = msg.m_source;
    let target_e: Endpoint = rd_i32(msg, 0);
    let priority = rd_i32(msg, 4);
    let quantum = rd_i32(msg, 8);

    sys_schedctl(system, target_e, 0); // claim: scheduler = SCHED
    policy::record(endpoint_proc(target_e).get(), priority as u8, quantum);
    sys_schedule(system, target_e, priority as u8, quantum);

    reply(caller_e, msg, OK);
}

/// `SCHEDULING_STOP` (PM/RS → SCHED): stop scheduling `target` and hand it back
/// to the kernel scheduler. Reply `OK` to the caller.
#[cfg_attr(test, allow(dead_code))]
fn handle_stop(system: Endpoint, msg: &mut Message) {
    let caller_e = msg.m_source;
    let target_e: Endpoint = rd_i32(msg, 0);

    sys_schedctl(system, target_e, SCHEDCTL_FLAG_KERNEL); // release
    policy::forget(endpoint_proc(target_e).get());

    reply(caller_e, msg, OK);
}

/// `SCHEDULING_SET_NICE` (PM/RS → SCHED): change `target`'s band only, preserving
/// the quantum recorded at `SCHEDULING_START`, and apply it via `SYS_SCHEDULE`.
/// Reply `OK` to the caller.
#[cfg_attr(test, allow(dead_code))]
fn handle_set_nice(system: Endpoint, msg: &mut Message) {
    let caller_e = msg.m_source;
    let target_e: Endpoint = rd_i32(msg, 0);
    let priority = rd_i32(msg, 4);

    // A renice changes the priority band only; `renice` keeps the proc's recorded
    // quantum (or registers at the default if unseen) and hands back the quantum
    // to re-schedule with. `None` only when the table is full and the proc is new.
    if let Some(quantum) = policy::renice(endpoint_proc(target_e).get(), priority as u8) {
        sys_schedule(system, target_e, priority as u8, quantum);
    }

    reply(caller_e, msg, OK);
}

/// Issue `SYS_SCHEDULE(target, priority, quantum)` to the kernel (SENDREC to
/// SYSTEM). The kernel sets the target's band + quantum and (re-)admits it to
/// the run queue. The reply code is ignored — a failure leaves the proc blocked,
/// which is the same outcome as not scheduling it.
#[cfg_attr(test, allow(dead_code))]
fn sys_schedule(system: Endpoint, target: Endpoint, priority: u8, quantum: i32) {
    let mut m = Message {
        m_source: 0,
        m_type: SYS_SCHEDULE,
        payload: [0u8; 96],
    };
    wr_i32(&mut m, 0, target);
    wr_i32(&mut m, 4, priority as i32);
    wr_i32(&mut m, 8, quantum);
    let _ = ipc_sendrec(system, &mut m);
}

/// Issue `SYS_SCHEDCTL(flags, target)` to the kernel (SENDREC to SYSTEM):
/// `flags = 0` claims the target for SCHED; `SCHEDCTL_FLAG_KERNEL` releases it.
#[cfg_attr(test, allow(dead_code))]
fn sys_schedctl(system: Endpoint, target: Endpoint, flags: i32) {
    let mut m = Message {
        m_source: 0,
        m_type: SYS_SCHEDCTL,
        payload: [0u8; 96],
    };
    wr_i32(&mut m, 0, flags);
    wr_i32(&mut m, 4, target);
    let _ = ipc_sendrec(system, &mut m);
}

/// Reply to a SENDREC caller with `code` in `m_type`.
#[cfg_attr(test, allow(dead_code))]
fn reply(caller_e: Endpoint, msg: &mut Message, code: i32) {
    msg.m_type = code;
    msg.m_source = 0; // kernel overwrites on delivery
    let _ = ipc_send(caller_e, msg);
}

/// Read a native-endian i32 from payload `off..off+4` (mirrors the VM/DS helpers).
#[cfg_attr(test, allow(dead_code))]
fn rd_i32(m: &Message, off: usize) -> i32 {
    i32::from_ne_bytes(
        m.payload[off..off + 4]
            .try_into()
            .expect("payload in range"),
    )
}

/// Write a native-endian i32 into payload `off..off+4`.
#[cfg_attr(test, allow(dead_code))]
fn wr_i32(m: &mut Message, off: usize, v: i32) {
    m.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
}

// The freestanding panic handler; under `cargo test` std supplies its own.
#[cfg(not(test))]
#[panic_handler]
fn panic(_: &core::panic::PanicInfo) -> ! {
    loop {
        core::hint::spin_loop()
    }
}

// ---------------------------------------------------------------------------
// SEF (System Event Framework) control message numbers — `m_type` values the
// server runtime (`server-rt`) intercepts before handing traffic to a server.
//
// These live in their own range distinct from `KERNEL_CALL` (`0x600`) and the
// VM request range (`VM_RQ_BASE = 0xC00`), and stay below the IPC
// `NOTIFY_MESSAGE` marker (`0x1000`), so neither a server's `m_type`
// dispatcher nor the SEF classifier can ever misroute. Numbering is
// minix.rs-specific (MINIX 3 carries these inside `lib/libsys/sef.c` request
// types rather than `com.h`).
//
// The RS heartbeat ("ping") deliberately gets NO number here: it is delivered
// as a NOTIFY, so it arrives with `m_type == NOTIFY_MESSAGE` and is keyed on
// `m_source == RS` instead (see `server-rt`'s `classify`). Do not add a
// `SEF_PING` — there is no payload room in a NOTIFY to carry one anyway.
// ---------------------------------------------------------------------------

/// Base for SEF control message `m_type` values.
pub const SEF_RQ_BASE: i32 = 0xD00;

/// RS → server: run the registered fresh-init callback. (Re-init / live-update
/// variants are deferred past Phase 4.)
pub const SEF_INIT: i32 = SEF_RQ_BASE;

/// PM/RS → server: deliver a signal. The signal number is in payload `0..4`
/// (i32, native-endian); `server-rt` dispatches it to the registered signal
/// handler.
pub const SEF_SIGNAL: i32 = SEF_RQ_BASE + 1;

/// Number of SEF control messages defined so far. Locks the classifier's
/// coverage in `server-rt` the way `NR_VMCTL_SUBCALLS` locks `do_vmctl`.
pub const NR_SEF_MSGS: usize = 2;

// The SEF range sits strictly above the VM request range (0xC00..0xC03) so a
// server's `m_type` dispatcher and the SEF classifier can never collide.
const _: () = assert!(SEF_RQ_BASE > VM_RQ_BASE + 3);
const _: () = assert!(SEF_RQ_BASE < crate::ipc_const::NOTIFY_MESSAGE);

// ---------------------------------------------------------------------------
// SCHED (scheduler) server request numbers — `m_type` values for messages
// addressed to the user-space SCHED server (slice 4.3).
//
// `SCHEDULING_NO_QUANTUM` is kernel-originated: when a SCHED-scheduled proc
// exhausts its quantum, the kernel sends it (with `m_source` = the preempted
// proc, so SCHED knows which proc to reschedule), exactly as it originates
// `VM_PAGEFAULT` for a faulter. The other three are PM/RS → SCHED requests
// (claim/release/renice a managed proc). Like the VM/DS ranges these are
// *server IPC requests*, not kernel calls, so they live in their own range
// distinct from `KERNEL_CALL` (`0x600`), VM (`0xC00`), SEF (`0xD00`), and DS
// (`0xE00`), and stay below the IPC `NOTIFY_MESSAGE` marker (`0x1000`) so the
// SEF classifier (which returns `Application` for them) can never misroute.
// Numbering is minix.rs-specific (MINIX 3 carries `SCHEDULING_*` in `com.h`).
// ---------------------------------------------------------------------------

/// Base for SCHED server request `m_type` values.
pub const SCHED_RQ_BASE: i32 = 0xF00;

/// Kernel → SCHED: the proc identified by `m_source` used up its full quantum.
/// SCHED applies its policy and re-admits the proc via `SYS_SCHEDULE`. Carries
/// no payload — `m_source` is the whole request.
pub const SCHEDULING_NO_QUANTUM: i32 = SCHED_RQ_BASE;

/// PM/RS → SCHED: start scheduling a proc. The target endpoint is in payload
/// `0..4` (i32), the initial priority in `4..8` (i32), and the quantum (ms) in
/// `8..12` (i32). SCHED claims the target via `SYS_SCHEDCTL` and assigns the
/// initial priority/quantum via `SYS_SCHEDULE`. (Driven by PM/RS from slice 4.5+.)
pub const SCHEDULING_START: i32 = SCHED_RQ_BASE + 1;

/// PM/RS → SCHED: stop scheduling the target (payload `0..4`, i32). SCHED hands
/// it back to the kernel scheduler via `SYS_SCHEDCTL(SCHEDCTL_FLAG_KERNEL)`.
pub const SCHEDULING_STOP: i32 = SCHED_RQ_BASE + 2;

/// PM/RS → SCHED: change the target's nice value. Target endpoint in payload
/// `0..4` (i32), new priority in `4..8` (i32). SCHED records it and applies it
/// via `SYS_SCHEDULE`.
pub const SCHEDULING_SET_NICE: i32 = SCHED_RQ_BASE + 3;

/// Number of SCHED server requests defined so far. Locks the dispatch-match
/// coverage in the SCHED server the way `NR_DS_REQUESTS` locks the DS server.
pub const NR_SCHED_MSGS: usize = 4;

// The SCHED range sits strictly above the DS range (0xE00..0xE02) and below the
// NOTIFY marker, so neither a server's `m_type` dispatcher nor the SEF
// classifier can ever collide with it.
const _: () = assert!(SCHED_RQ_BASE > DS_RQ_BASE + (NR_DS_REQUESTS as i32 - 1));
const _: () =
    assert!(SCHED_RQ_BASE + (NR_SCHED_MSGS as i32 - 1) < crate::ipc_const::NOTIFY_MESSAGE);

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn calls_are_contiguous_from_base() {
        let calls = [
            SYS_GETINFO,
            SYS_PRIVCTL,
            SYS_FORK,
            SYS_EXEC,
            SYS_EXIT,
            SYS_COPY,
            SYS_SAFECOPY,
            SYS_IRQCTL,
            SYS_VMCTL,
            SYS_SCHEDULE,
            SYS_SETALARM,
            SYS_TIMES,
            SYS_DIAGCTL,
            SYS_SETGRANT,
            SYS_SCHEDCTL,
        ];
        for (i, call) in calls.iter().enumerate() {
            assert_eq!(*call, KERNEL_CALL + i as i32);
        }
        assert_eq!(calls.len(), NR_KERN_CALLS_PHASE4);
    }

    #[test]
    fn kernel_call_base_matches_minix3() {
        assert_eq!(KERNEL_CALL, 0x600);
    }

    #[test]
    fn get_whoami_matches_minix3() {
        // Pinned by MINIX 3 include/minix/sysinfo.h; servers / musl wrappers
        // built later in the project depend on this value.
        assert_eq!(GET_WHOAMI, 12);
    }

