3	//! Priority-banded round-robin scheduler.
4	//!
5	//! Slice 2.4 grows `proc::sched` from the slice-2.3 stub (one fixed
6	//! current-proc tracker) into a real run-queue scheduler. Layout mirrors
7	//! MINIX 3 `kernel/proc.c:1605` (`enqueue`), `:1726` (`dequeue`), and
8	//! `:1795` (`pick_proc`), with two simplifications:
9	//!
10	//! - Queue linkage is a [`ProcNr`] index (`Proc::next_ready`) rather than a
11	//!   raw `struct proc *` — the project-wide convention from `CLAUDE.md`.
12	//! - No per-CPU run queues. Slice 2.4 is single-CPU.
13	//!
14	//! Concurrency model: the kernel runs DAIF-masked, so neither EL1 code nor
15	//! the IRQ handler can be interrupted by *another* IRQ before it finishes.
16	//! The IRQ stub itself is the only async writer; it runs to completion
17	//! before returning to EL0. That gives us the same single-threaded invariant
18	//! as the rest of the boot path, so we use the same `UnsafeCell` + `Sync`
19	//! newtype pattern documented on `ProcStorage` / `PrivStorage`.
20	
21	use core::cell::UnsafeCell;
22	use core::fmt::Write;
23	use core::sync::atomic::{AtomicI32, AtomicU64, Ordering};
24	
25	use minixrs_kernel_shared::ProcNr;
26	use minixrs_kernel_shared::endpoint::{Endpoint, NONE};
27	
28	use crate::arch::ArchRegisterFrame;
29	use crate::proc::Proc;
30	use crate::proc::flags::RTS_NO_QUANTUM;
31	use crate::proc::table::proc_slot_mut;
32	use crate::uart::Uart;
33	
34	/// Leading delegated quantum-exhaust events to trace explicitly, so the boot log
35	/// shows the kernel handing a SCHED-scheduled proc to its scheduler. Steady
36	/// state is dwarfed by stub C's SYS_GETINFO flood, so without a head carve-out
37	/// the modulo-100 `[ksys]` sampler would rarely catch SCHED's re-admit (same
38	/// reasoning as `ipc::TRACE_HEAD` and `do_vmctl::VMCTL_TRACE_HEAD`).
39	const NOQ_TRACE_HEAD: u64 = 6;
40	/// Count of delegated (non-kernel-scheduled) quantum-exhaust events, for the
41	/// head trace above.
42	static NOQ_COUNT: AtomicU64 = AtomicU64::new(0);
43	
44	/// Number of scheduling-priority bands. Matches the constants in
45	/// `proc::table` (`TASK_Q = 0`, `IDLE_Q = 15`).
46	pub const NR_SCHED_QUEUES: usize = 16;
47	
48	/// Currently-running process number. `i32::MIN` is the "no process running"
49	/// sentinel — chosen because it can never collide with a real `ProcNr`
50	/// (kernel tasks are `-5..=-1`, user processes are `0..NR_PROCS`).
51	pub static CURRENT_PROC_NR: AtomicI32 = AtomicI32::new(i32::MIN);
52	
53	const NO_PROC: i32 = i32::MIN;
54	
55	// ---------------------------------------------------------------------------
56	// Run-queue storage.
57	// ---------------------------------------------------------------------------
58	
59	struct RunQueues {
60	    head: [Option<ProcNr>; NR_SCHED_QUEUES],
61	    tail: [Option<ProcNr>; NR_SCHED_QUEUES],
62	}
63	
64	#[repr(transparent)]
65	struct RunQueueStorage(UnsafeCell<RunQueues>);
66	// SAFETY: single-CPU; the kernel runs DAIF-masked, so the only async writer
67	// is the IRQ stub, which runs to completion before returning to EL0. No
68	// concurrent access is possible.
69	unsafe impl Sync for RunQueueStorage {}
70	
71	static RUNQ: RunQueueStorage = RunQueueStorage(UnsafeCell::new(RunQueues {
72	    head: [None; NR_SCHED_QUEUES],
73	    tail: [None; NR_SCHED_QUEUES],
74	}));
75	
76	// ---------------------------------------------------------------------------
77	// Current-proc accessors.
78	// ---------------------------------------------------------------------------
79	
80	/// Borrow the currently-running process's slot.
81	///
82	/// SAFETY: caller must respect the single-threaded-boot invariant on
83	/// `PROC_TABLE`. The returned `&'static mut Proc` must not alias any other
84	/// reference into the table.
85	pub unsafe fn current_proc_mut() -> Option<&'static mut Proc> {
86	    let n = CURRENT_PROC_NR.load(Ordering::Relaxed);
87	    if n == NO_PROC {
88	        return None;
89	    }
90	    // SAFETY: forwarded — caller holds the no-aliasing invariant.
91	    unsafe { proc_slot_mut(ProcNr::new(n)) }
92	}
93	
94	// ---------------------------------------------------------------------------
95	// Run-queue operations.
96	// ---------------------------------------------------------------------------
97	
98	/// Append `nr` to the tail of its priority band's run queue.
99	///
100	/// Mirrors MINIX 3 `kernel/proc.c:1605` `enqueue`. Panics if the process is
101	/// already linked into a queue.
102	///
103	/// SAFETY: caller must hold the single-threaded-boot invariant; no other
104	/// mutable reference into `PROC_TABLE` or `RUNQ` may be live.
105	pub unsafe fn enqueue(nr: ProcNr) {
106	    let prio = unsafe {
107	        let p = proc_slot_mut(nr).expect("enqueue: nr out of range");
108	        assert!(p.next_ready.is_none(), "enqueue: process already queued");
109	        p.priority as usize
110	    };
111	    assert!(prio < NR_SCHED_QUEUES, "enqueue: priority out of range");
112	
113	    // SAFETY: RUNQ is a distinct static from PROC_TABLE; the prior
114	    // proc_slot_mut borrow has been dropped.
115	    let runq = unsafe { &mut *RUNQ.0.get() };
116	    match runq.tail[prio].replace(nr) {
117	        None => {
118	            // Queue was empty — set head too.
119	            runq.head[prio] = Some(nr);
120	        }
121	        Some(prev_tail) => {
122	            // SAFETY: prev_tail was in the queue, so its slot is valid.
123	            let tail_p =
124	                unsafe { proc_slot_mut(prev_tail).expect("enqueue: prev tail out of range") };
125	            tail_p.next_ready = Some(nr);
126	        }
127	    }
128	}
129	
130	/// Splice `nr` out of its priority band's run queue. No-op if not queued.
131	///
132	/// Mirrors MINIX 3 `kernel/proc.c:1726` `dequeue`. Slice 2.4's queues are
133	/// tiny (at most two entries), so the linear walk is fine.
134	///
135	/// SAFETY: caller must hold the single-threaded-boot invariant; no other
136	/// mutable reference into `PROC_TABLE` or `RUNQ` may be live.
137	pub unsafe fn dequeue(nr: ProcNr) {
138	    let prio = unsafe {
139	        proc_slot_mut(nr)
140	            .expect("dequeue: nr out of range")
141	            .priority as usize
142	    };
143	    // SAFETY: RUNQ is a distinct static from PROC_TABLE.
144	    let runq = unsafe { &mut *RUNQ.0.get() };
145	
146	    let mut prev: Option<ProcNr> = None;
147	    let mut cur = runq.head[prio];
148	    while let Some(c) = cur {
149	        // SAFETY: c was on the queue, so its slot is valid; no other live
150	        // reference into c's slot exists here.
151	        let next_after_c = unsafe {
152	            proc_slot_mut(c)
153	                .expect("dequeue: c out of range")
154	                .next_ready
155	        };
156	        if c == nr {
157	            // Clear the dequeued node's link.
158	            // SAFETY: same — single live reference at a time.
159	            unsafe {
160	                proc_slot_mut(c)
161	                    .expect("dequeue: c out of range")
162	                    .next_ready = None;
163	            }
164	            match prev {
165	                None => runq.head[prio] = next_after_c,
166	                Some(pn) => {
167	                    // SAFETY: pn was traversed already and is in the queue.
168	                    unsafe {
169	                        proc_slot_mut(pn)
170	                            .expect("dequeue: prev out of range")
171	                            .next_ready = next_after_c;
172	                    }
173	                }
174	            }
175	            if runq.tail[prio] == Some(c) {
176	                runq.tail[prio] = prev;
177	            }
178	            return;
179	        }
180	        prev = Some(c);
181	        cur = next_after_c;
182	    }
183	    // Not found — leave the queue untouched.
184	}
185	
186	/// Set bits in `p.rts_flags`; if the process transitions from runnable
187	/// (all-clear) to blocked, splice it out of the run queue.
188	///
189	/// Mirrors MINIX 3 `kernel/proc.h:206` `RTS_SET` — the macro that pairs
190	/// every `rts_flags |= …` with the corresponding `dequeue` call.
191	///
192	/// Caller pattern: hold `&mut Proc` to the affected slot, call this, then
193	/// let NLL drop the borrow before any subsequent `proc_slot_mut` against
194	/// the same slot — `dequeue` re-borrows internally.
195	///
196	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
197	/// invariant on `PROC_TABLE` and `RUNQ`. The borrow on `p` ends at this
198	/// function's last use of it (capturing `nr`); the subsequent `dequeue`
199	/// then re-enters cleanly.
200	pub unsafe fn rts_set(p: &mut Proc, flag: u32) {
201	    let was_runnable = p.rts_flags.load(Ordering::Relaxed) == 0;
202	    p.rts_flags.fetch_or(flag, Ordering::Relaxed);
203	    let nr = p.nr;
204	    if was_runnable {
205	        // SAFETY: caller's invariants; `p`'s borrow has been captured.
206	        unsafe { dequeue(nr) }
207	    }
208	}
209	
210	/// Clear bits in `p.rts_flags`; if the process transitions from blocked
211	/// to runnable (all bits cleared), splice it onto the tail of its
212	/// priority band's run queue.
213	///
214	/// Mirrors MINIX 3 `kernel/proc.h:216` `RTS_UNSET` — the converse pairing
215	/// to `RTS_SET`. Note that unblocking from RTS_SENDING while RTS_RECEIVING
216	/// is also set (mid-SENDREC) does *not* enqueue, because `prev & !flag`
217	/// is still non-zero.
218	///
219	/// SAFETY: caller must hold the same invariant as [`rts_set`].
220	pub unsafe fn rts_unset(p: &mut Proc, flag: u32) {
221	    let prev = p.rts_flags.fetch_and(!flag, Ordering::Relaxed);
222	    let nr = p.nr;
223	    let now_runnable = (prev & !flag) == 0;
224	    if now_runnable && prev != 0 {
225	        // SAFETY: caller's invariants; `p`'s borrow has been captured.
226	        unsafe { enqueue(nr) }
227	    }
228	}
229	
230	/// Return the head of the highest-priority non-empty run queue.
231	///
232	/// Mirrors MINIX 3 `kernel/proc.c:1795` `pick_proc`. Lower priority value =
233	/// higher priority, so we scan `0..NR_SCHED_QUEUES` and return the first
234	/// non-empty head.
235	pub fn pick_proc() -> Option<ProcNr> {
236	    // SAFETY: read-only snapshot under the single-threaded invariant.
237	    let runq = unsafe { &*RUNQ.0.get() };
238	    runq.head.iter().find_map(|&h| h)
239	}
240	
241	// ---------------------------------------------------------------------------
242	// Dispatch helpers.
243	// ---------------------------------------------------------------------------
244	
245	unsafe extern "C" {
246	    /// Restores `tpidr_el1`-pointed `ArchRegisterFrame` and erets into EL0.
247	    /// Defined in `kernel/src/arch/aarch64/trap.S`.
248	    fn el1_return_to_user() -> !;
249	}
250	
251	/// Park `&mut p.regs` in `TPIDR_EL1` so the SVC/IRQ entry paths and
252	/// `el1_return_to_user` can locate the current process's register frame.
253	///
254	/// SAFETY: `p` must be the slot whose number is currently parked in
255	/// `CURRENT_PROC_NR`. Caller must hold the single-threaded invariant.
256	unsafe fn set_tpidr_to(p: &mut Proc) {
257	    let regs_ptr: *mut ArchRegisterFrame = &mut p.regs;
258	    // SAFETY: TPIDR_EL1 is EL1-only and used only by our own SVC + IRQ stubs
259	    // and `el1_return_to_user`. No other code reads or writes it.
260	    unsafe {
261	        core::arch::asm!(
262	            "msr tpidr_el1, {0}",
263	            "isb",
264	            in(reg) regs_ptr,
265	            options(nomem, nostack, preserves_flags),
266	        );
267	    }
268	}
269	
270	/// Pick the highest-priority runnable process, park its register frame in
271	/// `TPIDR_EL1`, and flush any pending `MF_DELIVERMSG` into its user
272	/// buffer. Called at every EL1 → EL0 transition (SVC tail, IRQ tail,
273	/// first-dispatch from `run`).
274	///
275	/// Does *not* touch the run queue — `rts_set`/`rts_unset` keep blocked
276	/// procs off, and `reschedule` handles the quantum-rotation case
277	/// separately. If `pick_proc` finds nothing runnable, the previous
278	/// current stays current.
279	///
280	/// TODO(slice 2.6+): once IDLE is enqueued at boot, an empty run queue
281	/// becomes an invariant violation rather than the expected
282	/// "both-stubs-briefly-blocked" state we see in slice 2.5. At that
283	/// point, add `debug_assert!(pick_proc().is_some(), "run queue empty
284	/// — IDLE missing?")` so a regression that dequeues IDLE blows up
285	/// loudly. Today only stubs A/B are enqueued (see
286	/// `arch/aarch64/userland.rs::userland_bootstrap`), so the assert
287	/// would fire spuriously.
288	///
289	/// SAFETY: caller must hold the single-threaded / IRQ-masked invariant
290	/// and must not hold any other reference into `PROC_TABLE` while this
291	/// runs.
292	pub unsafe fn schedule_next() {
293	    let next_nr = match pick_proc() {
294	        Some(nr) => nr,
295	        None => return,
296	    };
297	    CURRENT_PROC_NR.store(next_nr.get(), Ordering::Relaxed);
298	    // SAFETY: next_nr came from the run queue; single-borrow.
299	    unsafe {
300	        let next = proc_slot_mut(next_nr).expect("schedule_next: next out of range");
301	        set_tpidr_to(next);
302	        // Per-proc TTBR0 + ASID install. Slice 3.1b: every runnable proc
303	        // is an EL0 stub with a real address space. This debug_assert gives
304	        // a richer per-proc message in debug builds; the authoritative
305	        // guard against a kernel task (asid=0) silently installing
306	        // TTBR0_EL1 = 0 lives in `switch_ttbr0_with_asid`, which asserts
307	        // unconditionally (the kernel only builds --release). The TTBR0
308	        // swap must happen *before* `flush_deliver_msg` — the flush writes
309	        // via the active TTBR0, so the new proc's AS must already be live.
310	        debug_assert!(
311	            next.ttbr0_pa != 0 && next.asid != 0,
312	            "schedule_next: proc nr={} has no AS (ttbr0_pa={:#x}, asid={})",
313	            next.nr.get(),
314	            next.ttbr0_pa,
315	            next.asid,
316	        );
317	        crate::arch::aarch64::mmu::switch_ttbr0_with_asid(next.ttbr0_pa, next.asid);
318	        crate::ipc::flush_deliver_msg(next);
319	    }
320	}
321	
322	/// First entry into EL0 from `kmain`.
323	///
324	/// Pre-condition: the desired-to-run procs have already been [`enqueue`]d.
325	/// Picks the highest-priority head, parks its frame in `TPIDR_EL1`,
326	/// flushes any pending `MF_DELIVERMSG`, and jumps to the assembly
327	/// restore-and-`eret` stub. Never returns.
328	///
329	/// SAFETY: at least one process must be enqueued (otherwise we stay on
330	/// boot context with no `TPIDR_EL1` set). Must be called with DAIF (I)
331	/// still masked at EL1; the per-proc SPSR carries the EL0 mask state
332	/// that takes effect on `eret`.
333	pub unsafe fn run() -> ! {
334	    // SAFETY: forwarded.
335	    unsafe { schedule_next() }
336	    // SAFETY: trap.S contract documented at `el1_return_to_user`.
337	    unsafe { el1_return_to_user() }
338	}
339	
340	/// Quantum-exhaust path: rotate the current proc to the tail of its
341	/// priority band (refilling its quantum), then pick the next runnable.
342	///
343	/// Called from `clock::tick` when the running proc's `quantum_left` hits
344	/// zero. The IRQ stub's trailing `bl el1_return_to_user` reads the
345	/// (possibly new) `TPIDR_EL1` and restores that frame, so the context
346	/// switch happens transparently.
347	///
348	/// SAFETY: caller holds the single-threaded invariant; called only from
349	/// IRQ context with no other PROC_TABLE / RUNQ borrows live.
350	pub unsafe fn reschedule() {
351	    let cur_raw = CURRENT_PROC_NR.load(Ordering::Relaxed);
352	    if cur_raw != NO_PROC {
353	        let cur_nr = ProcNr::new(cur_raw);
354	        // Read the delegation target first, then end the borrow (NLL) so the
355	        // dequeue/enqueue/send below can re-borrow `PROC_TABLE`.
356	        // SAFETY: single-threaded; cur_nr came from CURRENT_PROC_NR.
357	        let scheduler_e: Endpoint = unsafe {
358	            proc_slot_mut(cur_nr)
359	                .expect("reschedule: current out of range")
360	                .scheduler
361	        };
362	
363	        if scheduler_e == NONE {
364	            // Kernel-scheduled (the default): refill the quantum, clear
365	            // RTS_NO_QUANTUM, and rotate to the tail of the priority band.
366	            // SAFETY: single-threaded; cur_nr came from CURRENT_PROC_NR.
367	            let cur_runnable_after_refill = unsafe {
368	                let cur = proc_slot_mut(cur_nr).expect("reschedule: current out of range");
369	                cur.quantum_left = cur.quantum_ms as u64;
370	                cur.rts_flags.fetch_and(!RTS_NO_QUANTUM, Ordering::Relaxed);
371	                cur.rts_flags.load(Ordering::Relaxed) == 0
372	            };
373	            // Only rotate runnable cur. If cur is also blocked on something
374	            // else (e.g. IPC), `rts_set` already dequeued it — leave it off.
375	            if cur_runnable_after_refill {
376	                // SAFETY: cur_nr borrow above has been dropped.
377	                unsafe {
378	                    dequeue(cur_nr);
379	                    enqueue(cur_nr);
380	                }
381	            }
382	        } else {
383	            // Delegated to a user-space scheduler (slice 4.3). `clock::tick`
384	            // set RTS_NO_QUANTUM with a bare `fetch_or`, so cur is still on the
385	            // run queue and `pick_proc` (which ignores rts_flags) would re-pick
386	            // it. Dequeue it explicitly and leave RTS_NO_QUANTUM set — it stays
387	            // blocked until the scheduler re-admits it via SYS_SCHEDULE. Do NOT
388	            // refill the quantum; the scheduler assigns it.
389	            // SAFETY: cur_nr borrow above has been dropped; single-threaded.
390	            unsafe { dequeue(cur_nr) };
391	
392	            let n = NOQ_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
393	            if n <= NOQ_TRACE_HEAD {
394	                // SAFETY: single-threaded; sequential read-only borrow just for
395	                // the trace's identifying byte.
396	                let id = unsafe { proc_slot_mut(cur_nr).map(|p| p.name[0]).unwrap_or(b'?') };
397	                let _ = writeln!(
398	                    Uart::new(),
399	                    "[noq {n}] proc={} nr={} -> scheduler={scheduler_e:#x}",
400	                    id as char,
401	                    cur_nr.get(),
402	                );
403	            }
404	
405	            // Notify the scheduler. The wrapper materializes the proc-table
406	            // slice (no PROC_TABLE borrow is live here).
407	            crate::ipc::send_no_quantum(cur_nr, scheduler_e);
408	        }
409	    }
410	
411	    // SAFETY: same single-threaded invariant.
412	    unsafe { schedule_next() }
413	}
