261	// Access helpers. All return raw pointers — callers carry the single-threaded
262	// invariant.
263	// ---------------------------------------------------------------------------
264	
265	/// SAFETY: caller must ensure no other reference into `PROC_TABLE` exists.
266	pub(crate) unsafe fn proc_slot_mut(nr: ProcNr) -> Option<&'static mut Proc> {
267	    let idx = proc_index(nr)?;
268	    // SAFETY: `idx` is in-range; single-threaded boot context.
269	    let arr = unsafe { &mut *PROC_TABLE.0.get() };
270	    Some(&mut arr[idx])
