272	
273	/// SAFETY: caller must ensure no exclusive reference into `PROC_TABLE` exists.
274	pub(crate) unsafe fn proc_table_ref() -> &'static [Proc; N_PROC_SLOTS] {
275	    // SAFETY: single-threaded boot context.
