280	/// single `&mut [Proc]` down through every IPC primitive — avoiding the
281	/// two-`&mut`-from-one-`UnsafeCell` hazard that arises if each primitive
282	/// re-borrows individual slots via `proc_slot_mut`.
283	///
284	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
285	/// invariant and must not hold any other reference into `PROC_TABLE`
286	/// while the returned borrow is live.
287	pub(crate) unsafe fn proc_table_mut_slice() -> &'static mut [Proc; N_PROC_SLOTS] {
