289	    unsafe { &mut *PROC_TABLE.0.get() }
290	}
291	
292	/// SAFETY: caller must ensure no other reference into `PRIV_TABLE` exists.
293	pub(crate) unsafe fn priv_slot_mut(id: PrivId) -> Option<&'static mut Priv> {
294	    let idx = priv_index(id)?;
295	    // SAFETY: `idx` is in-range; single-threaded boot context.
296	    let arr = unsafe { &mut *PRIV_TABLE.0.get() };
297	    Some(&mut arr[idx])
298	}
299	
