301	pub(crate) unsafe fn priv_table_ref() -> &'static [Priv; NR_SYS_PROCS] {
302	    // SAFETY: single-threaded boot context.
303	    unsafe { &*PRIV_TABLE.0.get() }
304	}
305	
306	/// Borrow `PRIV_TABLE` mutably as a slice. Companion of
307	/// [`proc_table_mut_slice`] — `ipc::do_ipc` materializes both at once and
308	/// passes them down to the per-primitive handlers.
309	///
310	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
311	/// invariant and must not hold any other reference into `PRIV_TABLE`
312	/// while the returned borrow is live.
313	pub(crate) unsafe fn priv_table_mut_slice() -> &'static mut [Priv; NR_SYS_PROCS] {
