322	/// Populate `PROC_TABLE` and `PRIV_TABLE` from `IMAGE`.
323	///
324	/// Called exactly once from `kmain` during boot. Slice 2.4's scheduler will
325	/// assume one-shot init; double-calling would clobber any RTS bits the
326	/// scheduler has set since.
327	pub fn init() {
328	    init_empty_slots();
329	    init_boot_image();
330	}
331	
332	fn init_empty_slots() {
333	    // Give every slot a valid (nr, endpoint) so that index-based traversal
334	    // never sees a stale zero `nr` after `Proc::EMPTY` initialization.
335	    for i in 0..N_PROC_SLOTS {
336	        let nr = ProcNr::new(i as i32 - NR_TASKS as i32);
337	        // SAFETY: index in-range; single-threaded boot context; no other
338	        // references into PROC_TABLE exist at this point in `init`.
339	        let p = unsafe { proc_slot_mut(nr) }.expect("proc index in range");
340	        p.nr = nr;
341	        p.endpoint = boot_endpoint(nr);
342	        // EMPTY left rts_flags = RTS_SLOT_FREE — leave it that way.
343	    }
344	
345	    for i in 0..NR_SYS_PROCS {
346	        // SAFETY: index in-range; single-threaded boot context.
347	        let pr = unsafe { priv_slot_mut(PrivId::new(i as u16)) }.expect("priv index in range");
348	        pr.id = PrivId::new(i as u16);
349	    }
350	}
351	
352	fn init_boot_image() {
353	    // Active priv-slot count after population — the IPC bitmap for SRV_T
354	    // entries needs to enumerate every active slot.
355	    let n_active = N_IMAGE as u16;
356	
357	    for (slot, entry) in IMAGE.iter().enumerate() {
358	        let priv_id = PrivId::new(slot as u16);
359	        populate_priv(priv_id, entry, n_active);
360	        populate_proc(priv_id, entry);
361	    }
362	}
363	
364	fn populate_priv(id: PrivId, entry: &BootEntry, n_active: u16) {
365	    // SAFETY: priv index < NR_SYS_PROCS; single-threaded boot context; no
366	    // overlapping reference into PRIV_TABLE held across the call.
367	    let pr = unsafe { priv_slot_mut(id) }.expect("priv slot in range");
368	    pr.id = id;
369	    pr.proc_nr = Some(entry.nr);
370	    pr.flags = entry.priv_flags;
371	    pr.trap_mask = entry.trap_mask;
372	
373	    if entry.trap_mask == SRV_T {
374	        // SRV_T privs can send to every active slot. Set bits [0, n_active).
375	        fill_bits(&mut pr.ipc_to, n_active as usize);
376	        // SRV_T privs can issue every kernel call defined so far. This bound
377	        // tracks the highest `SYS_*` number; slice 4.3 widened it to admit
378	        // `SYS_SCHEDULE` / `SYS_SCHEDCTL` so SCHED may issue them.
379	        fill_bits(&mut pr.k_call_mask, NR_KERN_CALLS_PHASE4);
380	    }
381	    // Kernel-task slots leave ipc_to and k_call_mask zeroed.
382	
383	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
384	    pr.notify_pending.fill(0);
385	    pr.asyn_pending.fill(0);
386	}
387	
388	fn populate_proc(priv_id: PrivId, entry: &BootEntry) {
389	    // SAFETY: proc index in-range; single-threaded boot context; no
390	    // overlapping reference into PROC_TABLE held across the call.
391	    let p = unsafe { proc_slot_mut(entry.nr) }.expect("proc slot in range");
392	    p.priv_id = Some(priv_id);
393	    p.priority = entry.priority;
394	    p.quantum_ms = entry.quantum_ms;
395	    p.quantum_left = entry.quantum_ms as u64;
396	    p.endpoint = boot_endpoint(entry.nr);
397	    p.nr = entry.nr;
398	    // Boot procs start kernel-scheduled; a user-space scheduler claims them
399	    // later via `SYS_SCHEDCTL` (slice 4.3). `Proc::EMPTY` already zeroes this to
400	    // `NONE`, but set it explicitly so a future slot-reuse path can't inherit a
401	    // stale scheduler endpoint.
402	    p.scheduler = NONE;
403	
404	    // Copy name into the fixed-width field (truncates silently at PROC_NAME_LEN).
405	    let n = core::cmp::min(entry.name.len(), PROC_NAME_LEN - 1);
406	    p.name[..n].copy_from_slice(&entry.name[..n]);
407	    p.name[n..].fill(0);
408	
409	    let rts = if entry.runnable { 0 } else { RTS_NO_PRIV };
410	    p.rts_flags
411	        .store(rts, core::sync::atomic::Ordering::Relaxed);
412	}
413	
414	/// Set the lowest `n` bits in a `u32` bitmap.
415	fn fill_bits(map: &mut [u32], n: usize) {
416	    for i in 0..n {
417	        let word = i / 32;
418	        let bit = i % 32;
419	        if word < map.len() {
420	            map[word] |= 1 << bit;
421	        }
422	    }
423	}
424	
425	// Compile-time sanity that the bitmap sizing came out as expected.
426	const _: () = assert!(IPC_MAP_CHUNKS == 2);
427	const _: () = assert!(K_CALL_MASK_CHUNKS == 1);
428	
429	/// Number of slots in `PROC_TABLE` (for the dump helper).
430	pub const fn n_proc_slots() -> usize {
431	    N_PROC_SLOTS
432	}
433	
434	/// Number of slots in `IMAGE` (for the dump helper).
435	pub const fn n_image_slots() -> usize {
436	    N_IMAGE
437	}
438

