28	#[derive(Copy, Clone, Eq, PartialEq, Debug)]
29	pub enum RecvFlags {
30	    /// `RECEIVE` — block if no matching message is queued.
31	    Blocking,
32	    /// Non-blocking (no IPC primitive exposes this today, but the dispatch
33	    /// path passes it from the `RECEIVE` half of a SENDREC; symmetric to
34	    /// [`super::send::SendFlags::NonBlocking`]).
