71	        }
72	
73	        // 2. (Skip pending async — `mini_senda` is an ENOSYS stub.)
74	
75	        // 3. Walk caller_q for a sender matching src_e (or ANY).
76	        if let Some(matched) = walk_caller_q(proc_table, caller_idx, src_e) {
77	            return matched;
78	        }
79	    }
80	
81	    // Nothing to deliver.
82	    if flags == RecvFlags::NonBlocking {
83	        return ENOTREADY;
84	    }
85	
86	    if deadlock_check(&*proc_table, RECEIVE, caller_nr, src_e) {
87	        return ELOCKED;
88	    }
89	
90	    let caller = &mut proc_table[caller_idx];
91	    caller.getfrom_e = src_e;
92	    // SAFETY: single-threaded SVC invariant; no other borrow into
93	    // `proc_table` is live.
94	    unsafe { sched::rts_set(caller, RTS_RECEIVING) };
