96	}
97	
98	/// Look for the first pending notification matching `src_e` (or any, if
99	/// `src_e == ANY`) in `caller`'s `notify_pending` bitmap. Returns the
100	/// sender's endpoint and clears the bit on success.
101	fn take_pending_notification(
102	    proc_table: &[Proc; N_PROC_SLOTS],
103	    priv_table: &mut [Priv; NR_SYS_PROCS],
104	    caller_idx: usize,
105	    src_e: Endpoint,
106	) -> Option<Endpoint> {
107	    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
108	        return None;
109	    };
110	    let caller_priv_idx = caller_priv_id.as_usize();
111	
112	    // Snapshot the caller's notify_pending bitmap so the lookup loop can
113	    // read other priv_table slots without holding a mutable borrow.
114	    let pending_snapshot: [u32; IPC_MAP_CHUNKS] = priv_table[caller_priv_idx].notify_pending;
115	
116	    // TODO(slice 2.6+): when src_e != ANY, resolve priv_id directly
117	    // (endpoint → proc_index → priv_id) and test that single bit, rather
118	    // than scanning the whole bitmap. Current map is 64 bits so the walk
119	    // is fine, but cost grows with NR_SYS_PROCS.
120	    for chunk_idx in 0..pending_snapshot.len() {
121	        let mut chunk = pending_snapshot[chunk_idx];
122	        while chunk != 0 {
123	            let bit = chunk.trailing_zeros() as usize;
124	            let sender_priv_idx = chunk_idx * 32 + bit;
125	            if sender_priv_idx < NR_SYS_PROCS {
126	                if let Some(sender_nr) = priv_table[sender_priv_idx].proc_nr {
127	                    if let Some(sender_idx) = proc_index(sender_nr) {
128	                        let sender_e = proc_table[sender_idx].endpoint;
129	                        if src_e == ANY || src_e == sender_e {
130	                            // Clear bit and return.
131	                            priv_table[caller_priv_idx].notify_pending[chunk_idx] &= !(1u32 << bit);
132	                            return Some(sender_e);
133	                        }
134	                    }
135	                }
136	            }
137	            chunk &= chunk - 1; // pop lowest set bit and try next
138	        }
139	    }
140	    None
141	}
142	
143	/// Walk `caller_q` rooted at `proc_table[caller_idx]` for the first sender
144	/// matching `src_e` (or any, if `src_e == ANY`). On match, deliver the
145	/// sender's `send_msg` into the caller's `deliver_msg`, set `MF_DELIVERMSG`,
146	/// clear `MF_REPLY_PEND` (SENDREC completion), unblock the sender, splice
147	/// it out of the queue, and return `Some(OK)`. Returns `None` if nothing
148	/// matches.
149	fn walk_caller_q(
150	    proc_table: &mut [Proc; N_PROC_SLOTS],
151	    caller_idx: usize,
152	    src_e: Endpoint,
153	) -> Option<i32> {
154	    let mut prev: Option<usize> = None;
155	    let mut cur = proc_table[caller_idx].caller_q;
156	
157	    while let Some(sender_nr) = cur {
158	        let sender_idx = proc_index(sender_nr).expect("caller_q entry in range");
159	        let sender_e = proc_table[sender_idx].endpoint;
160	        let next = proc_table[sender_idx].q_link;
161	
162	        if src_e == ANY || src_e == sender_e {
163	            // Deliver: copy the buffered message into the caller's
164	            // deliver_msg (m_source was already stamped by mini_send).
165	            let msg = proc_table[sender_idx].send_msg;
166	            let caller = &mut proc_table[caller_idx];
167	            caller.deliver_msg = msg;
168	            caller.misc_flags |= MF_DELIVERMSG;
169	            caller.misc_flags &= !MF_REPLY_PEND;
170	
171	            // Splice sender out of the queue.
172	            match prev {
173	                None => proc_table[caller_idx].caller_q = next,
174	                Some(p_idx) => proc_table[p_idx].q_link = next,
175	            }
176	            {
177	                let sender = &mut proc_table[sender_idx];
178	                sender.q_link = None;
179	                // SAFETY: single-threaded SVC invariant.
180	                unsafe { sched::rts_unset(sender, RTS_SENDING) };
181	            }
182	            return Some(OK);
183	        }
184	
185	        prev = Some(sender_idx);
186	        cur = next;
187	    }
188	    None
189	}
