1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! SCHED scheduling policy + per-proc state table (slice 4.3).
4	//!
5	//! SCHED is minix.rs's user-space scheduler. The kernel run queue is
6	//! *delegatable*: when a SCHED-scheduled proc exhausts its quantum the kernel
7	//! sends `SCHEDULING_NO_QUANTUM`, and SCHED re-admits the proc via
8	//! `SYS_SCHEDULE`, choosing its priority band and quantum. This module holds the
9	//! per-proc policy state — a fixed `[SchedProc; CAP]` table wrapped in an
10	//! `UnsafeCell` newtype, exactly like the DS registry and the VM region table —
11	//! plus the pure policy helpers; the IPC/kernel-call glue lives in `main.rs`.
12	//!
13	//! **Policy (4.3): round-robin quantum refresh at a fixed managed band**
14	//! ([`USER_Q`]). Each `SCHEDULING_NO_QUANTUM` re-admits the proc at its recorded
15	//! priority with a fresh quantum. The managed band equals the boot servers' band
16	//! (`SRV_Q = 8`) so a CPU-bound managed proc round-robins with the
17	//! kernel-scheduled procs instead of sinking behind them. MINIX's priority aging
18	//! (drop a band on full-quantum use, periodically re-raised by `balance_queues`)
19	//! needs the per-proc alarm from `SYS_SETALARM` (slice 4.4): without the
20	//! compensating boost, dropping a band would starve the managed proc behind the
21	//! kernel-scheduled band-8 stubs, so it is deferred.
22	//!
23	//! The pure `*_in` helpers operate on a borrowed array and carry the host unit
24	//! tests; the thin `schedule_proc`/`record`/`forget` wrappers reach the static
25	//! and are the only `unsafe` here — the same split as the DS registry.
26	
27	use core::cell::UnsafeCell;
28	
29	/// Managed priority band. Matches the kernel's `SRV_Q` so a CPU-bound managed
30	/// proc round-robins with the kernel-scheduled boot procs / stubs rather than
31	/// sinking behind them (see the module note on deferred priority aging).
32	pub const USER_Q: u8 = 8;
33	
34	/// Quantum (kernel ticks) SCHED hands out. Small so a CPU-bound proc exhausts it
35	/// often, making the delegation round-trip visible in the boot trace.
36	pub const QUANTUM: i32 = 5;
37	
38	/// Per-proc policy-state table capacity. Covers every boot proc plus the stubs;
39	/// no allocator, so this is a hard cap (a new proc past it is simply left
40	/// unmanaged — it stays blocked, the user-space equivalent of "can't schedule").
41	const CAP: usize = 16;
42	
43	/// One managed proc's scheduling state. `in_use == false` marks a free slot.
44	#[derive(Copy, Clone)]
45	struct SchedProc {
46	    proc_nr: i32,
47	    priority: u8,
48	    quantum: i32,
49	    in_use: bool,
50	}
51	
52	impl SchedProc {
53	    const EMPTY: Self = Self {
54	        proc_nr: 0,
55	        priority: 0,
56	        quantum: 0,
57	        in_use: false,
58	    };
59	}
60	
61	/// Look up `proc_nr`'s `(priority, quantum)`, lazily registering it at the
62	/// default managed band + quantum if unseen (the `SCHEDULING_NO_QUANTUM` path —
63	/// the kernel pre-delegates a proc, so SCHED meets it for the first time on its
64	/// first no-quantum event). Returns `None` only if the table is full and
65	/// `proc_nr` is new.
66	fn schedule_in(t: &mut [SchedProc; CAP], proc_nr: i32) -> Option<(u8, i32)> {
67	    for e in t.iter() {
68	        if e.in_use && e.proc_nr == proc_nr {
69	            return Some((e.priority, e.quantum));
70	        }
71	    }
72	    for e in t.iter_mut() {
73	        if !e.in_use {
74	            *e = SchedProc {
75	                proc_nr,
76	                priority: USER_Q,
77	                quantum: QUANTUM,
78	                in_use: true,
79	            };
80	            return Some((USER_Q, QUANTUM));
81	        }
82	    }
83	    None
84	}
85	
86	/// Record (or update) `proc_nr`'s managed priority + quantum — the
87	/// `SCHEDULING_START` / `SCHEDULING_SET_NICE` path. Returns false only if the
88	/// table is full and `proc_nr` is new.
89	fn record_in(t: &mut [SchedProc; CAP], proc_nr: i32, priority: u8, quantum: i32) -> bool {
90	    for e in t.iter_mut() {
91	        if e.in_use && e.proc_nr == proc_nr {
92	            e.priority = priority;
93	            e.quantum = quantum;
94	            return true;
95	        }
96	    }
97	    for e in t.iter_mut() {
98	        if !e.in_use {
99	            *e = SchedProc {
100	                proc_nr,
101	                priority,
102	                quantum,
103	                in_use: true,
104	            };
105	            return true;
106	        }
107	    }
108	    false
109	}
110	
111	/// Change `proc_nr`'s managed priority, preserving its recorded quantum — the
112	/// `SCHEDULING_SET_NICE` path. A renice changes the band only; the time slice is
113	/// a per-proc property set at `SCHEDULING_START`, not a function of the nice
114	/// value. If `proc_nr` is unseen it is lazily registered at the given priority +
115	/// default [`QUANTUM`] (so a renice that precedes a start still takes effect).
116	/// Returns the effective quantum to hand `SYS_SCHEDULE`, or `None` only if the
117	/// table is full and `proc_nr` is new.
118	fn renice_in(t: &mut [SchedProc; CAP], proc_nr: i32, priority: u8) -> Option<i32> {
119	    for e in t.iter_mut() {
120	        if e.in_use && e.proc_nr == proc_nr {
121	            e.priority = priority;
122	            return Some(e.quantum);
123	        }
124	    }
125	    for e in t.iter_mut() {
126	        if !e.in_use {
127	            *e = SchedProc {
128	                proc_nr,
129	                priority,
130	                quantum: QUANTUM,
131	                in_use: true,
132	            };
133	            return Some(QUANTUM);
134	        }
135	    }
136	    None
137	}
138	
139	/// Stop managing `proc_nr` (the `SCHEDULING_STOP` path). No-op if absent.
140	fn forget_in(t: &mut [SchedProc; CAP], proc_nr: i32) {
141	    for e in t.iter_mut() {
142	        if e.in_use && e.proc_nr == proc_nr {
143	            *e = SchedProc::EMPTY;
144	            return;
145	        }
146	    }
147	}
148	
149	/// `UnsafeCell`-wrapped static policy table. See the module note for the
150	/// single-mutator invariant that makes the `Sync` impl sound.
151	#[repr(transparent)]
152	struct Table(UnsafeCell<[SchedProc; CAP]>);
153	
154	// SAFETY: SCHED is a single-threaded EL0 process with no interrupt handlers of
155	// its own; the table is only ever accessed from SCHED's straight-line receive
156	// loop, so there is never concurrent access.
157	unsafe impl Sync for Table {}
158	
159	static TABLE: Table = Table(UnsafeCell::new([SchedProc::EMPTY; CAP]));
160	
161	/// Look up (lazily registering at the default band) `proc_nr`'s scheduling
162	/// parameters. See [`schedule_in`].
163	#[cfg_attr(test, allow(dead_code))]
164	pub fn schedule_proc(proc_nr: i32) -> Option<(u8, i32)> {
165	    // SAFETY: single-mutator invariant (module note); no other reference into
166	    // the table is live during SCHED's straight-line loop.
167	    let t = unsafe { &mut *TABLE.0.get() };
168	    schedule_in(t, proc_nr)
169	}
170	
171	/// Record (or update) `proc_nr`'s managed priority + quantum. See [`record_in`].
172	#[cfg_attr(test, allow(dead_code))]
173	pub fn record(proc_nr: i32, priority: u8, quantum: i32) -> bool {
174	    // SAFETY: single-mutator invariant (module note).
175	    let t = unsafe { &mut *TABLE.0.get() };
176	    record_in(t, proc_nr, priority, quantum)
177	}
178	
179	/// Change `proc_nr`'s priority, preserving its recorded quantum. See
180	/// [`renice_in`].
181	#[cfg_attr(test, allow(dead_code))]
182	pub fn renice(proc_nr: i32, priority: u8) -> Option<i32> {
183	    // SAFETY: single-mutator invariant (module note).
184	    let t = unsafe { &mut *TABLE.0.get() };
185	    renice_in(t, proc_nr, priority)
186	}
187	
188	/// Stop managing `proc_nr`. See [`forget_in`].
189	#[cfg_attr(test, allow(dead_code))]
190	pub fn forget(proc_nr: i32) {
191	    // SAFETY: single-mutator invariant (module note).
192	    let t = unsafe { &mut *TABLE.0.get() };
193	    forget_in(t, proc_nr)
194	}
195	
196	#[cfg(test)]
197	mod tests {
198	    use super::*;
199	
200	    #[test]
201	    fn first_sight_registers_at_default_band() {
202	        let mut t = [SchedProc::EMPTY; CAP];
203	        assert_eq!(schedule_in(&mut t, 13), Some((USER_Q, QUANTUM)));
204	        // The slot is now in use and stable on the next lookup.
205	        assert_eq!(schedule_in(&mut t, 13), Some((USER_Q, QUANTUM)));
206	        let used = t.iter().filter(|e| e.in_use).count();
207	        assert_eq!(
208	            used, 1,
209	            "a repeat no-quantum must not consume a second slot"
210	        );
211	    }
212	
213	    #[test]
214	    fn record_then_schedule_returns_recorded_values() {
215	        let mut t = [SchedProc::EMPTY; CAP];
216	        assert!(record_in(&mut t, 9, 6, 20));
217	        assert_eq!(schedule_in(&mut t, 9), Some((6, 20)));
218	    }
219	
220	    #[test]
221	    fn record_updates_in_place() {
222	        let mut t = [SchedProc::EMPTY; CAP];
223	        assert!(record_in(&mut t, 9, 6, 20));
224	        assert!(record_in(&mut t, 9, 10, 5));
225	        assert_eq!(schedule_in(&mut t, 9), Some((10, 5)));
226	        let used = t.iter().filter(|e| e.in_use).count();
227	        assert_eq!(used, 1);
228	    }
229	
230	    #[test]
231	    fn forget_frees_the_slot() {
232	        let mut t = [SchedProc::EMPTY; CAP];
233	        schedule_in(&mut t, 13);
234	        forget_in(&mut t, 13);
235	        assert_eq!(t.iter().filter(|e| e.in_use).count(), 0);
236	        // forgetting an absent proc is a no-op
237	        forget_in(&mut t, 99);
238	        assert_eq!(t.iter().filter(|e| e.in_use).count(), 0);
239	    }
240	
241	    #[test]
242	    fn distinct_procs_coexist() {
243	        let mut t = [SchedProc::EMPTY; CAP];
244	        schedule_in(&mut t, 11);
245	        schedule_in(&mut t, 12);
246	        record_in(&mut t, 13, 4, 30);
247	        assert_eq!(schedule_in(&mut t, 11), Some((USER_Q, QUANTUM)));
248	        assert_eq!(schedule_in(&mut t, 12), Some((USER_Q, QUANTUM)));
249	        assert_eq!(schedule_in(&mut t, 13), Some((4, 30)));
250	    }
251	
252	    #[test]
253	    fn full_table_leaves_new_proc_unmanaged() {
254	        let mut t = [SchedProc::EMPTY; CAP];
255	        for i in 0..CAP as i32 {
256	            assert!(record_in(&mut t, i, USER_Q, QUANTUM));
257	        }
258	        // A new proc has nowhere to go.
259	        assert_eq!(schedule_in(&mut t, 100), None);
260	        assert!(!record_in(&mut t, 100, USER_Q, QUANTUM));
261	        // But an already-managed proc still resolves.
262	        assert_eq!(schedule_in(&mut t, 0), Some((USER_Q, QUANTUM)));
263	    }
264	
265	    #[test]
266	    fn renice_preserves_quantum() {
267	        // A proc started with a non-default quantum keeps it across a renice;
268	        // only the band changes.
269	        let mut t = [SchedProc::EMPTY; CAP];
270	        assert!(record_in(&mut t, 9, USER_Q, 20));
271	        assert_eq!(renice_in(&mut t, 9, 4), Some(20));
272	        assert_eq!(schedule_in(&mut t, 9), Some((4, 20)));
273	        let used = t.iter().filter(|e| e.in_use).count();
274	        assert_eq!(used, 1, "renice must not consume a second slot");
275	    }
276	
277	    #[test]
278	    fn renice_unseen_registers_at_default_quantum() {
279	        // A renice before any start lazily registers at the given band + default
280	        // quantum.
281	        let mut t = [SchedProc::EMPTY; CAP];
282	        assert_eq!(renice_in(&mut t, 13, 6), Some(QUANTUM));
283	        assert_eq!(schedule_in(&mut t, 13), Some((6, QUANTUM)));
284	    }
285	
286	    #[test]
287	    fn renice_full_table_leaves_new_proc_unmanaged() {
288	        let mut t = [SchedProc::EMPTY; CAP];
289	        for i in 0..CAP as i32 {
290	            assert!(record_in(&mut t, i, USER_Q, QUANTUM));
291	        }
292	        // A new proc has nowhere to go, even via renice.
293	        assert_eq!(renice_in(&mut t, 100, 4), None);
294	        // An already-managed proc reprioritizes in place, quantum intact.
295	        assert_eq!(renice_in(&mut t, 0, 4), Some(QUANTUM));
296	        assert_eq!(schedule_in(&mut t, 0), Some((4, QUANTUM)));
297	    }
298	}
