        // An already-managed proc reprioritizes in place, quantum intact.
        assert_eq!(renice_in(&mut t, 0, 4), Some(QUANTUM));
        assert_eq!(schedule_in(&mut t, 0), Some((4, QUANTUM)));
    }
}

