        for _ in 0..DEAD_THRESHOLD - 1 {
            assert_eq!(sweep_in(&mut t), 0);
        }
        assert_eq!(sweep_in(&mut t), 1);
        // Still dead on subsequent sweeps.
        assert_eq!(sweep_in(&mut t), 1);
    }

